
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_GI_G_DECLARACIONES_PRESENTADAS_FUN_ANUAL" ("NMRO_CNSCTVO", "ID_SJTO_IMPSTO", "VGNCIA", "ID_PRDO", "TRUNC(E.FCHA_PRSNTCION)", "'CLASIFICACION'", "'OPCION DE USO'", "'FECHA MAXIMA DE PRESENTACION'", "'NUMERO DE DECLARACION ANTERIOR'", "'1. NOMBRES Y APELLIDOS O RAZON SOCIAL'", "'2. TIPO DE IDENTIFICACION'", "'IDENTIFICACION'", "'3. DIRECCION DE NOTIFICACION'", "'DEPARTAMENTO'", "'MUNICIPIO O DISTRITO DE LA DIRECCION'", "'4. TELEFONO'", "'5. CORREO ELECTRONICO'", "'6. No.ESTABLECIMIENTOS'", "'AVISOS Y TABLEROS'", "'ES UN CONSORCIO O UNION TEMPORAL'", "'REALIZA ACTIVIDADES A TRAVES DE PATRIMONIO AUTONOMO'", "'?ESTA DECLARACION ES POR CANCELACION DEL ESTABLECIMIENTO?'", "'8. TOTAL INGRESOS ORDINARIOS Y EXTRAORDINARIOS DEL PERIODO EN TODO EL PAIS'", "'9. MENOS INGRESOS FUERA DE ESTE MUNICIPIO O DISTRITO'", "'10. TOTAL INGRESOS ORDINARIOS Y EXTRAORDINARIOS EN ESTE MUNICIPIO (renglon 8 menos 9)'", "'11. MENOS INGRESOS POR DEVOLUCIONES, REBAJAS, DESCUENTOS'", "'12. MENOS INGRESOS POR EXPORTACIONES'", "'13. MENOS INGRESOS POR VENTA DE ACTIVOS FIJOS'", "'14. MENOS INGRESOS POR ACTIVIDADES EXCLUIDAS O NO SUJETAS Y OTROS INGRESOS NO GRAVADOS'", "'15. MENOS INGRESOS POR OTRAS ACTIVIDADES EXENTAS EN ESTE MUNICIPIO O DISTRITO (POR ACUERDO)'", "'16. TOTAL INGRESOS GRAVABLES (renglon 10 menos 11, 12, 13, 14, 15)'", "'ACTIVIDADES GRAVADAS'", "'TARIFA ( por mil )'", "'INGRESOS GRAVADOS'", "'IMPUESTO'", "'TOTAL INGRESOS GRAVADOS'", "'17. TOTAL IMPUESTO'", "'18 GENERACION DE ENERGIA - CAPACIDAD INSTALADA KW:'", "'19. IMPUESTO LEY 56 DE 1981'", "'20. TOTAL IMPUESTO DE INDUSTRIA Y COMERCIO (renglon 17 + 19)'", "'21. IMPUESTO DE AVISOS Y TABLEROS (15% de renglon 20)'", "'22. PAGO POR UNIDADES COMERCIALES ADICIONALES DEL SECTOR FINANCIERO'", "'23. SOBRETASA BOMBERIL (Ley 1575 de 2012) (Si la hay, liquidala segun el acuerdo municipal o distrital)'", "'24. SOBRETASA DE SEGURIDAD (LEY 1421 de 2011) (Si la hay, liquidela segun el acuerdo municipal o distrital)'", "'25. TOTAL IMPUESTO A CARGO (RENGLON 20+21+22+23+24)'", "'26. MENOS VALOR DE EXENCION O EXONERACION SOBRE EL IMPUESTO Y NO SOBRE LOS INGRESOS'", "'27. MENOS RETENCIONES que le practicaron a favor de este municipio o distrito en este periodo'", "'28. MENOS AUTORRETENCIONES practicadas a favor de este municipio o distrito en este periodo'", "'29. MENOS ANTICIPO LIQUIDADO EN EL A?O ANTERIOR'", "'30. ANTICIPO DEL A?O SIGUIENTE (40% segun Acuerdo Municipal)'", "'TIPO SANCION'", "'TIPO CALCULO SANCION'", "'31. SANCIONES'", "'31. SANCIONES (SUGERIDA)'", "'32. MENOS SALDO QUE PAGO EN LA DECLARACION INICIAL ANTES DE CORRECCION'", "'33. TOTAL SALDO A CARGO (RENGLON 25-26-27-28-29+30+31-32)'", "'34. TOTAL SALDO A FAVOR (RENGLON 25-26-27-28-29+30+31-32) si el resultado es menor a cero'", "'35. VALOR A PAGAR'", "'36. DESCUENTO POR PRONTO PAGO (Si existe, liquidelo segun el Acuerdo Municipal o distrital)'", "'37. INTERESES DE MORA'", "'38. TOTAL A PAGAR (RENGLON 35-36+37)'", "'DESEO HACER APORTE VOLUNTARIO'", "'39. LIQUIDE EL VALOR DEL PAGO VOLUNTARIO (Segun instrucciones del municipio/distrito)'", "'Destino de mi aporte voluntario'", "'40. TOTAL A PAGAR CON PAGO VOLUNTARIO (Renglon 38 + 39)'", "'VALOR A PAGAR EN BANCOS'", "'NOMBRES Y APELLIDOS DEL DECLARANTE'", "'TIPO DE IDENTIFICACION DEL DECLARANTE'", "'N? IDENTIFICACION DEL DECLARANTE'", "'NOMBRES Y APELLIDOS CONTADOR O REVISOR FISCAL'", "'TIPO DE IDENTIFICACION DEL CONTADOR O REV FISCAL'", "'N? IDENTIFICACION DEL CONTADOR O REV FISCAL'", "'TARJETA PROFESIONAL'", "'REVISADO'") AS
  SELECT
        "NMRO_CNSCTVO", id_sjto_impsto, "VGNCIA", id_prdo, "TRUNC(E.FCHA_PRSNTCION)", "'CLASIFICACION'", "'OPCION DE USO'","'FECHA MAXIMA DE PRESENTACION'","'NUMERO DE DECLARACION ANTERIOR'","'1. NOMBRES Y APELLIDOS O RAZON SOCIAL'","'2. TIPO DE IDENTIFICACION'","'IDENTIFICACION'","'3. DIRECCION DE NOTIFICACION'","'DEPARTAMENTO'","'MUNICIPIO O DISTRITO DE LA DIRECCION'","'4. TELEFONO'","'5. CORREO ELECTRONICO'","'6. No.ESTABLECIMIENTOS'","'AVISOS Y TABLEROS'","'ES UN CONSORCIO O UNION TEMPORAL'","'REALIZA ACTIVIDADES A TRAVES DE PATRIMONIO AUTONOMO'","'?ESTA DECLARACION ES POR CANCELACION DEL ESTABLECIMIENTO?'","'8. TOTAL INGRESOS ORDINARIOS Y EXTRAORDINARIOS DEL PERIODO EN TODO EL PAIS'","'9. MENOS INGRESOS FUERA DE ESTE MUNICIPIO O DISTRITO'","'10. TOTAL INGRESOS ORDINARIOS Y EXTRAORDINARIOS EN ESTE MUNICIPIO (renglon 8 menos 9)'","'11. MENOS INGRESOS POR DEVOLUCIONES, REBAJAS, DESCUENTOS'","'12. MENOS INGRESOS POR EXPORTACIONES'","'13. MENOS INGRESOS POR VENTA DE ACTIVOS FIJOS'","'14. MENOS INGRESOS POR ACTIVIDADES EXCLUIDAS O NO SUJETAS Y OTROS INGRESOS NO GRAVADOS'","'15. MENOS INGRESOS POR OTRAS ACTIVIDADES EXENTAS EN ESTE MUNICIPIO O DISTRITO (POR ACUERDO)'","'16. TOTAL INGRESOS GRAVABLES (renglon 10 menos 11, 12, 13, 14, 15)'","'ACTIVIDADES GRAVADAS'","'TARIFA ( por mil )'","'INGRESOS GRAVADOS'","'IMPUESTO'","'TOTAL INGRESOS GRAVADOS'","'17. TOTAL IMPUESTO'","'18 GENERACION DE ENERGIA - CAPACIDAD INSTALADA KW:'","'19. IMPUESTO LEY 56 DE 1981'","'20. TOTAL IMPUESTO DE INDUSTRIA Y COMERCIO (renglon 17 + 19)'","'21. IMPUESTO DE AVISOS Y TABLEROS (15% de renglon 20)'","'22. PAGO POR UNIDADES COMERCIALES ADICIONALES DEL SECTOR FINANCIERO'","'23. SOBRETASA BOMBERIL (Ley 1575 de 2012) (Si la hay, liquidala segun el acuerdo municipal o distrital)'","'24. SOBRETASA DE SEGURIDAD (LEY 1421 de 2011) (Si la hay, liquidela segun el acuerdo municipal o distrital)'","'25. TOTAL IMPUESTO A CARGO (RENGLON 20+21+22+23+24)'","'26. MENOS VALOR DE EXENCION O EXONERACION SOBRE EL IMPUESTO Y NO SOBRE LOS INGRESOS'","'27. MENOS RETENCIONES que le practicaron a favor de este municipio o distrito en este periodo'","'28. MENOS AUTORRETENCIONES practicadas a favor de este municipio o distrito en este periodo'","'29. MENOS ANTICIPO LIQUIDADO EN EL A?O ANTERIOR'","'30. ANTICIPO DEL A?O SIGUIENTE (40% segun Acuerdo Municipal)'","'TIPO SANCION'","'TIPO CALCULO SANCION'","'31. SANCIONES'","'31. SANCIONES (SUGERIDA)'","'32. MENOS SALDO QUE PAGO EN LA DECLARACION INICIAL ANTES DE CORRECCION'","'33. TOTAL SALDO A CARGO (RENGLON 25-26-27-28-29+30+31-32)'","'34. TOTAL SALDO A FAVOR (RENGLON 25-26-27-28-29+30+31-32) si el resultado es menor a cero'","'35. VALOR A PAGAR'","'36. DESCUENTO POR PRONTO PAGO (Si existe, liquidelo segun el Acuerdo Municipal o distrital)'","'37. INTERESES DE MORA'","'38. TOTAL A PAGAR (RENGLON 35-36+37)'","'DESEO HACER APORTE VOLUNTARIO'","'39. LIQUIDE EL VALOR DEL PAGO VOLUNTARIO (Segun instrucciones del municipio/distrito)'","'Destino de mi aporte voluntario'","'40. TOTAL A PAGAR CON PAGO VOLUNTARIO (Renglon 38 + 39)'","'VALOR A PAGAR EN BANCOS'","'NOMBRES Y APELLIDOS DEL DECLARANTE'","'TIPO DE IDENTIFICACION DEL DECLARANTE'","'N? IDENTIFICACION DEL DECLARANTE'","'NOMBRES Y APELLIDOS CONTADOR O REVISOR FISCAL'","'TIPO DE IDENTIFICACION DEL CONTADOR O REV FISCAL'","'N? IDENTIFICACION DEL CONTADOR O REV FISCAL'","'TARJETA PROFESIONAL'","'REVISADO'"
    FROM
        (
            SELECT
                e.nmro_cnsctvo,
                e.id_sjto_impsto,
                e.vgncia,
                e.id_prdo,
                trunc(e.fcha_prsntcion),
                b.dscrpcion,
                dbms_lob.substr(a.vlor_dsplay, dbms_lob.getlength(a.vlor_dsplay), 1) AS vlor_dsplay
            FROM
                gi_g_declaraciones_detalle   a
                INNER JOIN gi_d_frmlrios_rgion_atrbto   b ON b.id_frmlrio_rgion_atrbto = a.id_frmlrio_rgion_atrbto
                INNER JOIN gi_d_formularios_region      c ON c.id_frmlrio_rgion = b.id_frmlrio_rgion
                INNER JOIN gi_d_formularios             d ON d.id_frmlrio       = c.id_frmlrio
                JOIN gi_g_declaraciones                 e ON a.id_dclrcion      = e.id_dclrcion
            WHERE
                /*a.id_dclrcion = 802435
                AND*/ d.id_frmlrio = 764
                AND b.cdgo_atrbto_tpo NOT IN (
                    'OCL'
                )
                AND e.cdgo_dclrcion_estdo = 'APL'
                AND e.fcha_prsntcion >= '01/01/2021'
                and e.fcha_prsntcion <= sysdate
            ORDER BY
                a.id_dclrcion DESC,
                c.orden,
                b.orden
        ) PIVOT (
            MAX ( vlor_dsplay )
            FOR ( dscrpcion )
            IN ( 'CLASIFICACION',
            'OPCION DE USO',
            'FECHA MAXIMA DE PRESENTACION',
            'NUMERO DE DECLARACION ANTERIOR',
            '1. NOMBRES Y APELLIDOS O RAZON SOCIAL',
            '2. TIPO DE IDENTIFICACION',
            'IDENTIFICACION',
            '3. DIRECCION DE NOTIFICACION',
            'DEPARTAMENTO',
            'MUNICIPIO O DISTRITO DE LA DIRECCION',
            '4. TELEFONO',
            '5. CORREO ELECTRONICO',
            '6. No.ESTABLECIMIENTOS',
            'AVISOS Y TABLEROS',
            'ES UN CONSORCIO O UNION TEMPORAL',
            'REALIZA ACTIVIDADES A TRAVES DE PATRIMONIO AUTONOMO',
            '?ESTA DECLARACION ES POR CANCELACION DEL ESTABLECIMIENTO?',
            '8. TOTAL INGRESOS ORDINARIOS Y EXTRAORDINARIOS DEL PERIODO EN TODO EL PAIS',
            '9. MENOS INGRESOS FUERA DE ESTE MUNICIPIO O DISTRITO',
            '10. TOTAL INGRESOS ORDINARIOS Y EXTRAORDINARIOS EN ESTE MUNICIPIO (renglon 8 menos 9)',
            '11. MENOS INGRESOS POR DEVOLUCIONES, REBAJAS, DESCUENTOS',
            '12. MENOS INGRESOS POR EXPORTACIONES',
            '13. MENOS INGRESOS POR VENTA DE ACTIVOS FIJOS',
            '14. MENOS INGRESOS POR ACTIVIDADES EXCLUIDAS O NO SUJETAS Y OTROS INGRESOS NO GRAVADOS',
            '15. MENOS INGRESOS POR OTRAS ACTIVIDADES EXENTAS EN ESTE MUNICIPIO O DISTRITO (POR ACUERDO)',
            '16. TOTAL INGRESOS GRAVABLES (renglon 10 menos 11, 12, 13, 14, 15)',
            'ACTIVIDADES GRAVADAS',
            'TARIFA ( por mil )',
            'INGRESOS GRAVADOS',
            'IMPUESTO',
            'TOTAL INGRESOS GRAVADOS',
            '17. TOTAL IMPUESTO',
            '18 GENERACION DE ENERGIA - CAPACIDAD INSTALADA KW:',
            '19. IMPUESTO LEY 56 DE 1981',
            '20. TOTAL IMPUESTO DE INDUSTRIA Y COMERCIO (renglon 17 + 19)',
            '21. IMPUESTO DE AVISOS Y TABLEROS (15% de renglon 20)',
            '22. PAGO POR UNIDADES COMERCIALES ADICIONALES DEL SECTOR FINANCIERO',
            '23. SOBRETASA BOMBERIL (Ley 1575 de 2012) (Si la hay, liquidala segun el acuerdo municipal o distrital)',
            '24. SOBRETASA DE SEGURIDAD (LEY 1421 de 2011) (Si la hay, liquidela segun el acuerdo municipal o distrital)',
            '25. TOTAL IMPUESTO A CARGO (RENGLON 20+21+22+23+24)',
            '26. MENOS VALOR DE EXENCION O EXONERACION SOBRE EL IMPUESTO Y NO SOBRE LOS INGRESOS',
            '27. MENOS RETENCIONES que le practicaron a favor de este municipio o distrito en este periodo',
            '28. MENOS AUTORRETENCIONES practicadas a favor de este municipio o distrito en este periodo',
            '29. MENOS ANTICIPO LIQUIDADO EN EL A?O ANTERIOR',
            '30. ANTICIPO DEL A?O SIGUIENTE (40% segun Acuerdo Municipal)',
            'TIPO SANCION',
            'TIPO CALCULO SANCION',
            '31. SANCIONES',
            '31. SANCIONES (SUGERIDA)',
            '32. MENOS SALDO QUE PAGO EN LA DECLARACION INICIAL ANTES DE CORRECCION',
            '33. TOTAL SALDO A CARGO (RENGLON 25-26-27-28-29+30+31-32)',
            '34. TOTAL SALDO A FAVOR (RENGLON 25-26-27-28-29+30+31-32) si el resultado es menor a cero',
            '35. VALOR A PAGAR',
            '36. DESCUENTO POR PRONTO PAGO (Si existe, liquidelo segun el Acuerdo Municipal o distrital)',
            '37. INTERESES DE MORA',
            '38. TOTAL A PAGAR (RENGLON 35-36+37)',
            'DESEO HACER APORTE VOLUNTARIO',
            '39. LIQUIDE EL VALOR DEL PAGO VOLUNTARIO (Segun instrucciones del municipio/distrito)',
            'Destino de mi aporte voluntario',
            '40. TOTAL A PAGAR CON PAGO VOLUNTARIO (Renglon 38 + 39)',
            'VALOR A PAGAR EN BANCOS',
            'NOMBRES Y APELLIDOS DEL DECLARANTE',
            'TIPO DE IDENTIFICACION DEL DECLARANTE',
            'N? IDENTIFICACION DEL DECLARANTE',
            'NOMBRES Y APELLIDOS CONTADOR O REVISOR FISCAL',
            'TIPO DE IDENTIFICACION DEL CONTADOR O REV FISCAL',
            'N? IDENTIFICACION DEL CONTADOR O REV FISCAL',
            'TARJETA PROFESIONAL',
            'REVISADO' )
        );

